  1	import {
  2	  ExpandableSectionToggle,
  3	  Toolbar,
  4	  ToolbarContent,
  5	  ToolbarItem,
  6	  Tooltip,
  7	  ValidatedOptions
  8	} from '@patternfly/react-core';
  9	import { CompressIcon, ExpandIcon } from '@patternfly/react-icons';
 10	import * as _ from 'lodash';
 11	import * as React from 'react';
 12	import { useTranslation } from 'react-i18next';
 13	import { Filter, FilterCompare, FilterDefinition, Filters } from '../../model/filters';
 14	import { useNetflowContext } from '../../model/netflow-context';
 15	import { autoCompleteCache } from '../../utils/autocomplete-cache';
 16	import { findFilter, matcher } from '../../utils/filter-definitions';
 17	import { Indicator } from '../../utils/filters-helper';
 18	import { localStorageShowFiltersKey, useLocalStorage } from '../../utils/local-storage-hook';
 19	import { QueryOptionsDropdown, QueryOptionsProps } from '../dropdowns/query-options-dropdown';
 20	import './filters-toolbar.css';
 21	import { FilterSearchInput } from './filters/filter-search-input';
 22	import { FiltersChips } from './filters/filters-chips';
 23	import { QuickFilters } from './filters/quick-filters';
 24	import { LinksOverflow } from './links-overflow';
 25	
 26	export interface FiltersToolbarProps {
 27	  id: string;
 28	  filters?: Filters;
 29	  forcedFilters?: Filters | null;
 30	  skipTipsDelay?: boolean;
 31	  setFilters: (v: Filters) => void;
 32	  clearFilters: () => void;
 33	  resetFilters: () => void;
 34	  queryOptionsProps: QueryOptionsProps;
 35	  isFullScreen: boolean;
 36	  setFullScreen: (b: boolean) => void;
 37	}
 38	
 39	export type Direction = 'source' | 'destination' | undefined;
 40	
 41	export const FiltersToolbar: React.FC<FiltersToolbarProps> = ({
 42	  id,
 43	  filters,
 44	  forcedFilters,
 45	  skipTipsDelay,
 46	  setFilters,
 47	  clearFilters,
 48	  resetFilters,
 49	  isFullScreen,
 50	  setFullScreen,
 51	  ...props
 52	}) => {
 53	  const { t } = useTranslation('plugin__netobserv-plugin');
 54	  const { caps, config } = useNetflowContext();
 55	  const quickFilters = caps.quickFilters;
 56	  const filterDefinitions = caps.filterDefs;
 57	
 58	  const [message, setMessage] = React.useState<string | undefined>();
 59	  const [indicator, setIndicator] = React.useState<Indicator>(ValidatedOptions.default);
 60	
 61	  const [searchInputValue, setSearchInputValue] = React.useState('');
 62	
 63	  const getDefaultFilter = React.useCallback((defs: FilterDefinition[]): FilterDefinition => {
 64	    // Parent guarantees non-empty definitions
 65	    return findFilter(defs, 'src_namespace') || defs[0];
 66	  }, []);
 67	
 68	  const getDefaultDirection = React.useCallback((filter: FilterDefinition): Direction => {
 69	    // Set direction based on filter's category or id prefix
 70	    if (filter.category === 'source' || filter.id.startsWith('src_')) {
 71	      return 'source';
 72	    } else if (filter.category === 'destination' || filter.id.startsWith('dst_')) {
 73	      return 'destination';
 74	    }
 75	    return undefined;
 76	  }, []);
 77	
 78	  const [filter, setFilter] = React.useState<FilterDefinition>(() => getDefaultFilter(filterDefinitions));
 79	  const [direction, setDirection] = React.useState<Direction>(() =>
 80	    getDefaultDirection(getDefaultFilter(filterDefinitions))
 81	  );
 82	  const [compare, setCompare] = React.useState<FilterCompare>(FilterCompare.equal);
 83	  const [value, setValue] = React.useState<string>('');
 84	
 85	  const [showFilters, setShowFilters] = useLocalStorage<boolean>(localStorageShowFiltersKey, true);
 86	
 87	  // Safe filter setter that validates the filter exists in filterDefinitions
 88	  const setSafeFilter = React.useCallback(
 89	    (f: FilterDefinition | null | undefined) => {
 90	      if (!f) {
 91	        // If null/undefined, use default filter
 92	        setFilter(getDefaultFilter(filterDefinitions));
 93	      } else if (filterDefinitions.find(fd => fd.id === f.id)) {
 94	        // If filter exists in definitions, use it
 95	        setFilter(f);
 96	      } else {
 97	        // If filter doesn't exist, fallback to default
 98	        setFilter(getDefaultFilter(filterDefinitions));
 99	      }
100	    },
101	    [filterDefinitions, getDefaultFilter]
102	  );
103	
104	  // Update filter if filterDefinitions changes and current filter is no longer valid
105	  React.useEffect(() => {
106	    if (!filterDefinitions.find(fd => fd.id === filter.id)) {
107	      const newFilter = getDefaultFilter(filterDefinitions);
108	      setFilter(newFilter);
109	      // Sync direction with the new filter
110	      setDirection(getDefaultDirection(newFilter));
111	    }
112	  }, [filterDefinitions, filter, getDefaultFilter, getDefaultDirection]);
113	
114	  // reset and delay message state to trigger tooltip properly
115	  const setMessageWithDelay = React.useCallback(
116	    (m: string | undefined) => {
117	      if (skipTipsDelay) {
118	        setMessage(m);
119	      } else {
120	        setMessage(undefined);
121	        setTimeout(() => {
122	          setMessage(m);
123	        }, 100);
124	      }
125	    },
126	    [skipTipsDelay]
127	  );
128	
129	  const editValue = React.useCallback((f: Filter, v: string) => {
130	    setSearchInputValue(matcher(f.def.id, [v], f.compare));
131	  }, []);
132	
133	  const getFilterToolbar = React.useCallback(() => {
134	    return (
135	      <ToolbarItem className="flex-start">
136	        <Tooltip
137	          //css hide tooltip here to avoid render issue
138	          className={`filters-tooltip${_.isEmpty(message) ? '-empty' : ''}`}
139	          isVisible={!_.isEmpty(message)}
140	          content={message}
141	          trigger={_.isEmpty(message) ? 'manual' : 'click'}
142	          enableFlip={false}
143	          position={'top'}
144	        >
145	          <FilterSearchInput
146	            config={config}
147	            filterDefinitions={filterDefinitions}
148	            filters={filters}
149	            indicator={indicator}
150	            direction={direction}
151	            filter={filter}
152	            compare={compare}
153	            value={value}
154	            setValue={setValue}
155	            setCompare={setCompare}
156	            setFilter={setSafeFilter}
157	            setDirection={setDirection}
158	            setIndicator={setIndicator}
159	            searchInputValue={searchInputValue}
160	            setSearchInputValue={setSearchInputValue}
161	            setFilters={setFilters}
162	            setMessage={setMessageWithDelay}
163	          />
164	        </Tooltip>
165	      </ToolbarItem>
166	    );
167	  }, [
168	    config,
169	    compare,
170	    direction,
171	    filter,
172	    filterDefinitions,
173	    filters,
174	    indicator,
175	    message,
176	    searchInputValue,
177	    setFilters,
178	    setMessageWithDelay,
179	    setSafeFilter,
180	    value
181	  ]);
182	
183	  const isForced = !_.isEmpty(forcedFilters);
184	  const filtersOrForced = isForced ? forcedFilters : filters;
185	  const defaultFilters = quickFilters.filter(qf => qf.default).flatMap(qf => qf.filters);
186	
187	  const countActiveFilters = (filtersOrForced?.list || []).reduce((prev, cur) => prev + cur.values.length, 0);
188	  let showHideText: string | undefined;
189	  if (countActiveFilters > 0) {
190	    showHideText = showFilters ? t('Hide filters') : t('Show {{countActiveFilters}} filters', { countActiveFilters });
191	  } else if (defaultFilters.length > 0) {
192	    showHideText = showFilters ? t('Hide filters') : t('Show filters');
193	  }
194	  return (
195	    <>
196	      <Toolbar data-test={id} id={id}>
197	        <ToolbarContent data-test={`${id}-search-filters`} id={`${id}-search-filters`} toolbarId={id}>
198	          <ToolbarItem className="flex-start">
199	            <QueryOptionsDropdown {...props.queryOptionsProps} />
200	          </ToolbarItem>
201	          {!isForced && quickFilters.length > 0 && (
202	            <ToolbarItem className="flex-start">
203	              <QuickFilters
204	                quickFilters={quickFilters}
205	                activeFilters={filters?.list || []}
206	                setFilters={list => setFilters({ ...filters!, list })}
207	              />
208	            </ToolbarItem>
209	          )}
210	          {!isForced && getFilterToolbar()}
211	          {showHideText && countActiveFilters > 0 && (
212	            <ToolbarItem className="flex-start">
213	              <ExpandableSectionToggle
214	                data-test="show-filters-button"
215	                id="show-filters-button"
216	                className="overflow-button"
217	                isExpanded={showFilters}
218	                onToggle={isExpanded => setShowFilters(isExpanded)}
219	              >
220	                {showHideText}
221	              </ExpandableSectionToggle>
222	            </ToolbarItem>
223	          )}
224	          <ToolbarItem className="flex-start">
225	            <LinksOverflow
226	              id={'filters-more-options'}
227	              items={[
228	                {
229	                  id: 'fullscreen',
230	                  label: isFullScreen ? t('Collapse') : t('Expand'),
231	                  onClick: () => setFullScreen(!isFullScreen),
232	                  icon: isFullScreen ? <CompressIcon /> : <ExpandIcon />
233	                },
234	                {
235	                  id: 'set-default-filters',
236	                  label: t('Default filters'),
237	                  onClick: () => {
238	                    resetFilters();
239	                    autoCompleteCache.clear();
240	                  },
241	                  enabled: countActiveFilters === 0
242	                }
243	              ]}
244	            />
245	          </ToolbarItem>
246	        </ToolbarContent>
247	      </Toolbar>
248	      {showFilters && countActiveFilters > 0 && (
249	        <Toolbar data-test={`${id}-chips`} id={`${id}-chips`}>
250	          <ToolbarContent toolbarId={`${id}-chips`}>
251	            <FiltersChips
252	              isForced={isForced}
253	              filters={filtersOrForced!}
254	              setDirection={setDirection}
255	              setFilters={setFilters}
256	              editValue={editValue}
257	              clearFilters={clearFilters}
258	              resetFilters={resetFilters}
259	              quickFilters={quickFilters}
260	              filterDefinitions={filterDefinitions}
261	            />
262	          </ToolbarContent>
263	        </Toolbar>
264	      )}
265	    </>
266	  );
267	};
268	
269	export default FiltersToolbar;

