  2	import * as React from 'react';
  3	
  4	import { FilterDefinitionSample } from '../../../../components/__tests-data__/filters';
  5	import { defaultConfig } from '../../../../model/config';
  6	import { NetflowContext, NetflowContextValue } from '../../../../model/netflow-context';
  7	import { ConfigCapabilities } from '../../../../utils/netflow-capabilities-hook';
  8	import FiltersToolbar, { FiltersToolbarProps } from '../../../toolbar/filters-toolbar';
  9	
 10	const testCaps = {
 11	  allowLoki: true,
 12	  allowProm: true,
 13	  isFlow: true,
 14	  isConnectionTracking: true,
 15	  isDNSTracking: false,
 16	  isFlowRTT: false,
 17	  isPktDrop: true,
 18	  isPromOnly: false,
 19	  availableScopes: [],
 20	  allowedMetricTypes: [],
 21	  availablePanels: [],
 22	  selectedPanels: [],
 23	  availableColumns: [],
 24	  selectedColumns: [],
 25	  filterDefs: FilterDefinitionSample,
 26	  quickFilters: [],
 27	  defaultFilters: [],
 28	  flowQuery: {},
 29	  fetchFunctions: {}
 30	} as unknown as ConfigCapabilities;
 31	
 32	import { defaultNetflowMetrics } from '../../../../api/loki';
 33	import { FetchCallbacks } from '../../../../model/netflow-context';
 34	
 35	const testFetchCallbacks: FetchCallbacks = {
 36	  metricsRef: { current: defaultNetflowMetrics },
 37	  setFlows: jest.fn(),
 38	  setMetrics: jest.fn(),
 39	  setError: jest.fn()
 40	};
