 42	const testContext: NetflowContextValue = {
 43	  caps: testCaps,
 44	  config: defaultConfig,
 45	  k8sModels: {},
 46	  fetchCallbacks: testFetchCallbacks
 47	};
 48	
 49	describe('<FiltersToolbar />', () => {
 50	  const props: FiltersToolbarProps = {
 51	    filters: { match: 'all', list: [] },
 52	    forcedFilters: undefined,
 53	    skipTipsDelay: true,
 54	    setFilters: jest.fn(),
 55	    clearFilters: jest.fn(),
 56	    resetFilters: jest.fn(),
