 58	    queryOptionsProps: {
 59	      limit: 100,
 60	      recordType: 'allConnections',
 61	      dataSource: 'auto',
 62	      allowFlow: true,
 63	      allowConnection: true,
 64	      allowProm: true,
 65	      allowLoki: true,
 66	      allowPktDrops: true,
 67	      useTopK: false,
 68	      packetLoss: 'all',
 69	      setLimit: jest.fn(),
 70	      setPacketLoss: jest.fn(),
 71	      setRecordType: jest.fn(),
 72	      setDataSource: jest.fn()
 73	    },
 74	    isFullScreen: false,
 75	    setFullScreen: jest.fn()
 76	  };
 77	
 78	  beforeEach(() => {
 79	    props.setFilters = jest.fn();
 80	    props.clearFilters = jest.fn();
 81	  });
 82	
 83	  const withContext = (ui: React.ReactElement) => (
 84	    <NetflowContext.Provider value={testContext}>{ui}</NetflowContext.Provider>
 85	  );
