 88	    const { container } = render(withContext(<FiltersToolbar {...props} />));
 89	    expect(container.querySelector('.pf-v6-c-toolbar')).toBeTruthy();
 90	  });
 91	
 92	  it('should open and close search popper', async () => {
 93	    const { container } = render(withContext(<FiltersToolbar {...props} />));
 94	
 95	    await act(async () => {
 96	      fireEvent.click(container.querySelector('[aria-label="Open advanced search"]')!);
 97	    });
 98	    await waitFor(() => {
 99	      expect(document.querySelector('#filter-popper')).toBeTruthy();
100	    });
101	
102	    await act(async () => {
103	      fireEvent.click(container.querySelector('[aria-label="Open advanced search"]')!);
104	    });
105	
106	    expect(props.setFilters).toHaveBeenCalledTimes(0);
